   112→// TransitionContext provides read-only context for transitions that need
   113→// to inspect session state without mutating it.
   114→type TransitionContext struct {
   115→	HasFilesTouched    bool // len(FilesTouched) > 0
   116→	IsRebaseInProgress bool // .git/rebase-merge/ or .git/rebase-apply/ exists
