   270→// ApplyTransition applies a TransitionResult to state: sets the new phase
   271→// unconditionally, then executes all actions. Common actions
   272→// (UpdateLastInteraction, ClearEndedAt) always run regardless of handler
   273→// errors so that bookkeeping fields stay consistent with the new phase.
   274→// Strategy-specific handler actions stop on the first error; subsequent
   275→// handler actions are skipped but common actions continue. Returns the
   276→// first handler error, or nil.
   277→func ApplyTransition(state *State, result TransitionResult, handler ActionHandler) error {
   278→	state.Phase = result.NewPhase
   279→
   280→	var handlerErr error
   281→	for _, action := range result.Actions {
   282→		switch action {
   283→		// Common actions: always applied, even after a handler error.
   284→		case ActionUpdateLastInteraction:
   285→			now := time.Now()
   286→			state.LastInteractionTime = &now
   287→		case ActionClearEndedAt:
   288→			state.EndedAt = nil
   289→
   290→		// Strategy-specific actions: skip remaining after the first handler error.
   291→		case ActionCondense:
   292→			if handlerErr == nil {
   293→				if err := handler.HandleCondense(state); err != nil {
   294→					handlerErr = fmt.Errorf("%s: %w", action, err)
   295→				}
   296→			}
   297→		case ActionCondenseIfFilesTouched:
   298→			if handlerErr == nil {
   299→				if err := handler.HandleCondenseIfFilesTouched(state); err != nil {
   300→					handlerErr = fmt.Errorf("%s: %w", action, err)
   301→				}
   302→			}
   303→		case ActionDiscardIfNoFiles:
   304→			if handlerErr == nil {
   305→				if err := handler.HandleDiscardIfNoFiles(state); err != nil {
   306→					handlerErr = fmt.Errorf("%s: %w", action, err)
   307→				}
   308→			}
   309→		case ActionWarnStaleSession:
   310→			if handlerErr == nil {
   311→				if err := handler.HandleWarnStaleSession(state); err != nil {
   312→					handlerErr = fmt.Errorf("%s: %w", action, err)
   313→				}
   314→			}
   315→		default:
   316→			if handlerErr == nil {
   317→				handlerErr = fmt.Errorf("unhandled action: %s", action)
   318→			}
   319→		}
   320→	}
   321→	return handlerErr
   322→}
