   324→// MermaidDiagram generates a Mermaid state diagram from the transition table.
   325→// The diagram is derived by calling Transition() for representative context
   326→// variants per phase/event, so it stays in sync with the implementation.
   327→func MermaidDiagram() string {
   328→	var b strings.Builder
   329→	b.WriteString("stateDiagram-v2\n")
   330→
   331→	// State declarations with descriptions.
   332→	b.WriteString("    state \"IDLE\" as idle\n")
   333→	b.WriteString("    state \"ACTIVE\" as active\n")
   334→	b.WriteString("    state \"ENDED\" as ended\n")
   335→	b.WriteString("\n")
   336→
   337→	// Context variants for GitCommit: rebase, files/no-files.
   338→	type contextVariant struct {
   339→		label string
   340→		ctx   TransitionContext
   341→	}
   342→
   343→	// For each phase/event, generate edges.
   344→	for _, phase := range allPhases {
   345→		for _, event := range allEvents {
   346→			var variants []contextVariant
   347→			switch {
   348→			case event == EventGitCommit && phase == PhaseEnded:
   349→				// HasFilesTouched only affects PhaseEnded transitions;
   350→				// other phases produce identical edges for both values.
   351→				variants = []contextVariant{
   352→					{"[files]", TransitionContext{HasFilesTouched: true}},
   353→					{"[no files]", TransitionContext{HasFilesTouched: false}},
   354→					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
   355→				}
   356→			case event == EventGitCommit:
   357→				variants = []contextVariant{
   358→					{"", TransitionContext{}},
   359→					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
   360→				}
   361→			default:
   362→				variants = []contextVariant{
   363→					{"", TransitionContext{}},
   364→				}
   365→			}
   366→
   367→			for _, v := range variants {
   368→				result := Transition(phase, event, v.ctx)
   369→
   370→				// Build edge label.
   371→				label := event.String()
   372→				if v.label != "" {
   373→					label += " " + v.label
   374→				}
   375→				if len(result.Actions) > 0 {
   376→					actionNames := make([]string, 0, len(result.Actions))
   377→					for _, a := range result.Actions {
   378→						actionNames = append(actionNames, a.String())
   379→					}
   380→					label += " / " + strings.Join(actionNames, ", ")
   381→				}
   382→
   383→				from := string(phase)
   384→				to := string(result.NewPhase)
   385→
   386→				fmt.Fprintf(&b, "    %s --> %s : %s\n", from, to, label)
   387→			}
   388→		}
   389→	}
   390→
   391→	return b.String()
   392→}
