    63→// CapturePrePromptState captures current untracked files and transcript position before a prompt
    64→// and saves them to a state file.
    65→// Works correctly from any subdirectory within the repository.
    66→// The transcriptPath parameter is optional - if empty, transcript position won't be captured.
    67→func CapturePrePromptState(sessionID, transcriptPath string) error {
    68→	if sessionID == "" {
    69→		sessionID = unknownSessionID
    70→	}
    71→
    72→	// Get absolute path for tmp directory
    73→	tmpDirAbs, err := paths.AbsPath(paths.EntireTmpDir)
    74→	if err != nil {
    75→		tmpDirAbs = paths.EntireTmpDir // Fallback to relative
    76→	}
