   123→// CaptureGeminiPrePromptState captures current untracked files and transcript position
   124→// before a prompt for Gemini sessions. This is called by the BeforeAgent hook.
   125→// The transcriptPath is the path to the Gemini session transcript (JSON format).
   126→func CaptureGeminiPrePromptState(sessionID, transcriptPath string) error {
   127→	if sessionID == "" {
   128→		sessionID = unknownSessionID
   129→	}
   130→
   131→	// Get absolute path for tmp directory
   132→	tmpDirAbs, err := paths.AbsPath(paths.EntireTmpDir)
   133→	if err != nil {
   134→		tmpDirAbs = paths.EntireTmpDir // Fallback to relative
   135→	}
   136→
   137→	// Create tmp directory if it doesn't exist
   138→	if err := os.MkdirAll(tmpDirAbs, 0o750); err != nil {
   139→		return fmt.Errorf("failed to create tmp directory: %w", err)
   140→	}
   141→
   142→	// Get list of untracked files (excluding .entire directory itself)
   143→	untrackedFiles, err := getUntrackedFilesForState()
   144→	if err != nil {
   145→		return fmt.Errorf("failed to get untracked files: %w", err)
   146→	}
   147→
   148→	// Get transcript position (message count and last message ID) for Gemini
   149→	var startMessageIndex int
   150→	var lastMessageID string
   151→	if transcriptPath != "" {
   152→		// Read transcript and extract both message count and last message ID
   153→		if data, readErr := os.ReadFile(transcriptPath); readErr == nil && len(data) > 0 { //nolint:gosec // Reading from controlled transcript path
   154→			var transcript struct {
   155→				Messages []struct {
   156→					ID string `json:"id"`
   157→				} `json:"messages"`
   158→			}
   159→			if jsonErr := json.Unmarshal(data, &transcript); jsonErr == nil {
   160→				startMessageIndex = len(transcript.Messages)
   161→				if startMessageIndex > 0 {
   162→					lastMessageID = transcript.Messages[startMessageIndex-1].ID
   163→				}
   164→			} else {
   165→				fmt.Fprintf(os.Stderr, "Warning: failed to parse transcript for message tracking: %v\n", jsonErr)
   166→			}
   167→		}
   168→	}
   169→
   170→	// Create state file
   171→	stateFile := prePromptStateFile(sessionID)
   172→	state := PrePromptState{
   173→		SessionID:                sessionID,
   174→		Timestamp:                time.Now().UTC().Format(time.RFC3339),
   175→		UntrackedFiles:           untrackedFiles,
   176→		StartMessageIndex:        startMessageIndex,
   177→		LastTranscriptIdentifier: lastMessageID,
   178→	}
   179→
   180→	data, err := json.MarshalIndent(state, "", "  ")
   181→	if err != nil {
   182→		return fmt.Errorf("failed to marshal state: %w", err)
   183→	}
   184→
   185→	if err := os.WriteFile(stateFile, data, 0o600); err != nil {
   186→		return fmt.Errorf("failed to write state file: %w", err)
   187→	}
   188→
   189→	fmt.Fprintf(os.Stderr, "Captured Gemini state before prompt: %d untracked files, transcript position: %d (last msg id: %s)\n", len(untrackedFiles), startMessageIndex, lastMessageID)
   190→	return nil
   191→}
