   457→// preTaskFilePrefix is the prefix for pre-task state files
   458→const preTaskFilePrefix = "pre-task-"
   459→
   460→// FindActivePreTaskFile finds an active pre-task file in .entire/tmp/ and returns
   461→// the parent Task's tool_use_id. Returns ("", false) if no pre-task file exists.
   462→// When multiple pre-task files exist (nested subagents), returns the most recently
   463→// modified one.
   464→// Works correctly from any subdirectory within the repository.
   465→func FindActivePreTaskFile() (taskToolUseID string, found bool) {
   466→	tmpDirAbs, err := paths.AbsPath(paths.EntireTmpDir)
   467→	if err != nil {
   468→		tmpDirAbs = paths.EntireTmpDir // Fallback to relative
   469→	}
   470→	entries, err := os.ReadDir(tmpDirAbs)
   471→	if err != nil {
   472→		return "", false
   473→	}
   474→
   475→	var latestFile string
   476→	var latestTime time.Time
   477→
   478→	for _, entry := range entries {
   479→		if entry.IsDir() {
   480→			continue
   481→		}
   482→		name := entry.Name()
   483→		if !strings.HasPrefix(name, preTaskFilePrefix) || !strings.HasSuffix(name, ".json") {
   484→			continue
   485→		}
   486→
   487→		// Check modification time for nested subagent handling
   488→		info, err := entry.Info()
   489→		if err != nil {
   490→			continue
   491→		}
   492→		if latestFile == "" || info.ModTime().After(latestTime) {
   493→			latestFile = name
   494→			latestTime = info.ModTime()
   495→		}
   496→	}
   497→
   498→	if latestFile == "" {
   499→		return "", false
   500→	}
   501→
   502→	// Extract tool_use_id from filename: pre-task-<tool_use_id>.json
   503→	toolUseID := strings.TrimPrefix(latestFile, preTaskFilePrefix)
   504→	toolUseID = strings.TrimSuffix(toolUseID, ".json")
   505→	return toolUseID, true
   506→}
