   177→// ReadSession reads a session from Claude's storage (JSONL transcript file).
   178→// The session data is stored in NativeData as raw JSONL bytes.
   179→// ModifiedFiles is computed by parsing the transcript.
   180→func (c *ClaudeCodeAgent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) {
   181→	if input.SessionRef == "" {
   182→		return nil, errors.New("session reference (transcript path) is required")
   183→	}
   184→
   185→	// Read the raw JSONL file
   186→	data, err := os.ReadFile(input.SessionRef)
   187→	if err != nil {
   188→		return nil, fmt.Errorf("failed to read transcript: %w", err)
   189→	}
   190→
   191→	// Parse to extract computed fields
   192→	lines, err := transcript.ParseFromBytes(data)
   193→	if err != nil {
   194→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
   195→	}
   196→
   197→	return &agent.AgentSession{
   198→		SessionID:     input.SessionID,
   199→		AgentName:     c.Name(),
   200→		SessionRef:    input.SessionRef,
   201→		StartTime:     time.Now(),
   202→		NativeData:    data,
   203→		ModifiedFiles: ExtractModifiedFiles(lines),
   204→	}, nil
   205→}
