     5→// AgentSession represents a coding session's data.
     6→// Each agent stores data in its native format (JSONL, SQLite, Markdown, etc.)
     7→// and only the originating agent can read/write it.
     8→//
     9→// Design: Sessions are NOT interoperable between agents. A session created by
    10→// Claude Code can only be read/written by Claude Code. This simplifies the
    11→// implementation as we don't need format conversion.
    12→//
    13→//nolint:revive // AgentSession is clearer than Session in context of the package
    14→type AgentSession struct {
    15→	SessionID  string
    16→	AgentName  AgentName
    17→	RepoPath   string
    18→	SessionRef string // Path/reference to session in agent's storage
    19→	StartTime  time.Time
    20→
    21→	// NativeData holds the session content in the agent's native format.
    22→	// Only the originating agent can interpret this data.
    23→	// Examples:
    24→	//   - Claude Code: raw JSONL bytes
    25→	//   - Cursor: serialized SQLite rows
    26→	//   - Aider: Markdown content
    27→	NativeData []byte
    28→
    29→	// Computed fields - populated by the agent when reading
    30→	ModifiedFiles []string
    31→	NewFiles      []string
    32→	DeletedFiles  []string
    33→
    34→	// Optional normalized entries - agents may populate this if needed
    35→	// for operations that benefit from structured access
    36→	Entries []SessionEntry
    37→}
