    39→// SessionEntry represents a single entry in the session
    40→type SessionEntry struct {
    41→	UUID      string
    42→	Type      EntryType
    43→	Timestamp time.Time
    44→	Content   string
    45→
    46→	// Tool-specific fields
    47→	ToolName      string
