   121→func (s *AgentSession) FindToolResultUUID(toolUseID string) (string, bool) {
   122→	for _, entry := range s.Entries {
   123→		if entry.Type == EntryTool && entry.UUID == toolUseID {
   124→			return entry.UUID, true
   125→		}
   126→	}
