    18→)
    19→
    20→//nolint:gochecknoinits // Agent self-registration is the intended pattern
    21→func init() {
    22→	agent.Register(agent.AgentNameClaudeCode, NewClaudeCodeAgent)
    23→}
    24→
    25→// ClaudeCodeAgent implements the Agent interface for Claude Code.
    26→//
    27→//nolint:revive // ClaudeCodeAgent is clearer than Agent in this context
    28→type ClaudeCodeAgent struct{}
    29→
    30→// NewClaudeCodeAgent creates a new Claude Code agent instance.
    31→func NewClaudeCodeAgent() agent.Agent {
    32→	return &ClaudeCodeAgent{}
    33→}
    34→
    35→// Name returns the agent registry key.
    36→func (c *ClaudeCodeAgent) Name() agent.AgentName {
    37→	return agent.AgentNameClaudeCode
    38→}
    39→
    40→// Type returns the agent type identifier.
    41→func (c *ClaudeCodeAgent) Type() agent.AgentType {
    42→	return agent.AgentTypeClaudeCode
    43→}
    44→
    45→// Description returns a human-readable description.
    46→func (c *ClaudeCodeAgent) Description() string {
    47→	return "Claude Code - Anthropic's CLI coding assistant"
    48→}
    49→
    50→// DetectPresence checks if Claude Code is configured in the repository.
    51→func (c *ClaudeCodeAgent) DetectPresence() (bool, error) {
    52→	// Get repo root to check for .claude directory
    53→	// This is needed because the CLI may be run from a subdirectory
    54→	repoRoot, err := paths.RepoRoot()
    55→	if err != nil {
    56→		// Not in a git repo, fall back to CWD-relative check
    57→		repoRoot = "."
    58→	}
    59→
    60→	// Check for .claude directory
    61→	claudeDir := filepath.Join(repoRoot, ".claude")
    62→	if _, err := os.Stat(claudeDir); err == nil {
    63→		return true, nil
    64→	}
    65→	// Check for .claude/settings.json
    66→	settingsFile := filepath.Join(repoRoot, ".claude", "settings.json")
    67→	if _, err := os.Stat(settingsFile); err == nil {
    68→		return true, nil
    69→	}
    70→	return false, nil
    71→}
    72→
    73→// GetHookConfigPath returns the path to Claude's hook config file.
    74→func (c *ClaudeCodeAgent) GetHookConfigPath() string {
    75→	return ".claude/settings.json"
    76→}
    77→
    78→// SupportsHooks returns true as Claude Code supports lifecycle hooks.
    79→func (c *ClaudeCodeAgent) SupportsHooks() bool {
    80→	return true
    81→}
    82→
    83→// ParseHookInput parses Claude Code hook input from stdin.
    84→func (c *ClaudeCodeAgent) ParseHookInput(hookType agent.HookType, reader io.Reader) (*agent.HookInput, error) {
    85→	data, err := io.ReadAll(reader)
    86→	if err != nil {
    87→		return nil, fmt.Errorf("failed to read input: %w", err)
    88→	}
    89→
    90→	if len(data) == 0 {
    91→		return nil, errors.New("empty input")
    92→	}
    93→
    94→	input := &agent.HookInput{
    95→		HookType:  hookType,
    96→		Timestamp: time.Now(),
    97→		RawData:   make(map[string]interface{}),
    98→	}
    99→
   100→	// Parse based on hook type
   101→	switch hookType {
   102→	case agent.HookUserPromptSubmit:
   103→		var raw userPromptSubmitRaw
   104→		if err := json.Unmarshal(data, &raw); err != nil {
   105→			return nil, fmt.Errorf("failed to parse user prompt submit: %w", err)
   106→		}
   107→		input.SessionID = raw.SessionID
   108→		input.SessionRef = raw.TranscriptPath
   109→		input.UserPrompt = raw.Prompt
   110→
   111→	case agent.HookSessionStart, agent.HookSessionEnd, agent.HookStop:
   112→		var raw sessionInfoRaw
   113→		if err := json.Unmarshal(data, &raw); err != nil {
   114→			return nil, fmt.Errorf("failed to parse session info: %w", err)
   115→		}
   116→		input.SessionID = raw.SessionID
   117→		input.SessionRef = raw.TranscriptPath
   118→
   119→	case agent.HookPreToolUse:
   120→		var raw taskHookInputRaw
   121→		if err := json.Unmarshal(data, &raw); err != nil {
   122→			return nil, fmt.Errorf("failed to parse pre-tool input: %w", err)
   123→		}
   124→		input.SessionID = raw.SessionID
   125→		input.SessionRef = raw.TranscriptPath
   126→		input.ToolUseID = raw.ToolUseID
   127→		input.ToolInput = raw.ToolInput
   128→
   129→	case agent.HookPostToolUse:
   130→		var raw postToolHookInputRaw
   131→		if err := json.Unmarshal(data, &raw); err != nil {
   132→			return nil, fmt.Errorf("failed to parse post-tool input: %w", err)
   133→		}
   134→		input.SessionID = raw.SessionID
   135→		input.SessionRef = raw.TranscriptPath
   136→		input.ToolUseID = raw.ToolUseID
   137→		input.ToolInput = raw.ToolInput
   138→		// Store agent ID in raw data for Task tool results
   139→		if raw.ToolResponse.AgentID != "" {
   140→			input.RawData["agent_id"] = raw.ToolResponse.AgentID
   141→		}
   142→	}
   143→
   144→	return input, nil
   145→}
   146→
   147→// GetSessionID extracts the session ID from hook input.
   148→func (c *ClaudeCodeAgent) GetSessionID(input *agent.HookInput) string {
   149→	return input.SessionID
   150→}
   151→
   152→// ResolveSessionFile returns the path to a Claude session file.
   153→// Claude names files directly as <id>.jsonl.
   154→func (c *ClaudeCodeAgent) ResolveSessionFile(sessionDir, agentSessionID string) string {
   155→	return filepath.Join(sessionDir, agentSessionID+".jsonl")
   156→}
   157→
   158→// ProtectedDirs returns directories that Claude uses for config/state.
   159→func (c *ClaudeCodeAgent) ProtectedDirs() []string { return []string{".claude"} }
   160→
   161→// GetSessionDir returns the directory where Claude stores session transcripts.
   162→func (c *ClaudeCodeAgent) GetSessionDir(repoPath string) (string, error) {
   163→	// Check for test environment override
   164→	if override := os.Getenv("ENTIRE_TEST_CLAUDE_PROJECT_DIR"); override != "" {
   165→		return override, nil
   166→	}
   167→
   168→	homeDir, err := os.UserHomeDir()
   169→	if err != nil {
   170→		return "", fmt.Errorf("failed to get home directory: %w", err)
   171→	}
   172→
   173→	projectDir := SanitizePathForClaude(repoPath)
   174→	return filepath.Join(homeDir, ".claude", "projects", projectDir), nil
   175→}
   176→
   177→// ReadSession reads a session from Claude's storage (JSONL transcript file).
   178→// The session data is stored in NativeData as raw JSONL bytes.
   179→// ModifiedFiles is computed by parsing the transcript.
   180→func (c *ClaudeCodeAgent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) {
   181→	if input.SessionRef == "" {
   182→		return nil, errors.New("session reference (transcript path) is required")
   183→	}
   184→
   185→	// Read the raw JSONL file
   186→	data, err := os.ReadFile(input.SessionRef)
   187→	if err != nil {
   188→		return nil, fmt.Errorf("failed to read transcript: %w", err)
   189→	}
   190→
   191→	// Parse to extract computed fields
   192→	lines, err := transcript.ParseFromBytes(data)
   193→	if err != nil {
   194→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
   195→	}
   196→
   197→	return &agent.AgentSession{
   198→		SessionID:     input.SessionID,
   199→		AgentName:     c.Name(),
   200→		SessionRef:    input.SessionRef,
   201→		StartTime:     time.Now(),
   202→		NativeData:    data,
   203→		ModifiedFiles: ExtractModifiedFiles(lines),
   204→	}, nil
   205→}
   206→
   207→// WriteSession writes a session to Claude's storage (JSONL transcript file).
   208→// Uses the NativeData field which contains raw JSONL bytes.
   209→// The session must have been created by Claude Code (AgentName check).
   210→func (c *ClaudeCodeAgent) WriteSession(session *agent.AgentSession) error {
   211→	if session == nil {
   212→		return errors.New("session is nil")
   213→	}
   214→
   215→	// Verify this session belongs to Claude Code
   216→	if session.AgentName != "" && session.AgentName != c.Name() {
   217→		return fmt.Errorf("session belongs to agent %q, not %q", session.AgentName, c.Name())
   218→	}
   219→
   220→	if session.SessionRef == "" {
   221→		return errors.New("session reference (transcript path) is required")
   222→	}
   223→
   224→	if len(session.NativeData) == 0 {
   225→		return errors.New("session has no native data to write")
   226→	}
   227→
   228→	// Write the raw JSONL data
   229→	if err := os.WriteFile(session.SessionRef, session.NativeData, 0o600); err != nil {
   230→		return fmt.Errorf("failed to write transcript: %w", err)
   231→	}
   232→
   233→	return nil
   234→}
   235→
   236→// FormatResumeCommand returns the command to resume a Claude Code session.
   237→func (c *ClaudeCodeAgent) FormatResumeCommand(sessionID string) string {
   238→	return "claude -r " + sessionID
   239→}
   240→
   241→// Session helper methods - work on AgentSession with Claude's native JSONL data
   242→
   243→// GetLastUserPrompt extracts the last user prompt from the session.
   244→// Requires NativeData to be populated (call ReadSession first).
   245→func (c *ClaudeCodeAgent) GetLastUserPrompt(session *agent.AgentSession) string {
   246→	if session == nil || len(session.NativeData) == 0 {
   247→		return ""
   248→	}
   249→
   250→	lines, err := transcript.ParseFromBytes(session.NativeData)
   251→	if err != nil {
   252→		return ""
   253→	}
   254→
   255→	return ExtractLastUserPrompt(lines)
   256→}
   257→
   258→// TruncateAtUUID returns a new session truncated at the given UUID (inclusive).
   259→// This is used for rewind operations to restore transcript state.
   260→// Requires NativeData to be populated.
   261→func (c *ClaudeCodeAgent) TruncateAtUUID(session *agent.AgentSession, uuid string) (*agent.AgentSession, error) {
   262→	if session == nil {
   263→		return nil, errors.New("session is nil")
   264→	}
   265→
   266→	if len(session.NativeData) == 0 {
   267→		return nil, errors.New("session has no native data")
   268→	}
   269→
   270→	if uuid == "" {
   271→		// No truncation needed, return copy
   272→		return &agent.AgentSession{
   273→			SessionID:     session.SessionID,
   274→			AgentName:     session.AgentName,
   275→			RepoPath:      session.RepoPath,
   276→			SessionRef:    session.SessionRef,
   277→			StartTime:     session.StartTime,
   278→			NativeData:    session.NativeData,
   279→			ModifiedFiles: session.ModifiedFiles,
   280→		}, nil
   281→	}
   282→
   283→	// Parse, truncate, re-serialize
   284→	lines, err := transcript.ParseFromBytes(session.NativeData)
   285→	if err != nil {
   286→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
   287→	}
   288→
   289→	truncated := TruncateAtUUID(lines, uuid)
   290→
   291→	newData, err := SerializeTranscript(truncated)
   292→	if err != nil {
   293→		return nil, fmt.Errorf("failed to serialize truncated transcript: %w", err)
   294→	}
   295→
   296→	return &agent.AgentSession{
   297→		SessionID:     session.SessionID,
   298→		AgentName:     session.AgentName,
   299→		RepoPath:      session.RepoPath,
   300→		SessionRef:    session.SessionRef,
   301→		StartTime:     session.StartTime,
   302→		NativeData:    newData,
   303→		ModifiedFiles: ExtractModifiedFiles(truncated),
   304→	}, nil
   305→}
   306→
   307→// FindCheckpointUUID finds the UUID of the message containing the tool_result
   308→// for the given tool use ID. Used for task checkpoint rewind.
   309→// Returns the UUID and true if found, empty string and false otherwise.
   310→func (c *ClaudeCodeAgent) FindCheckpointUUID(session *agent.AgentSession, toolUseID string) (string, bool) {
   311→	if session == nil || len(session.NativeData) == 0 {
   312→		return "", false
   313→	}
   314→
   315→	lines, err := transcript.ParseFromBytes(session.NativeData)
   316→	if err != nil {
   317→		return "", false
   318→	}
   319→
   320→	return FindCheckpointUUID(lines, toolUseID)
   321→}
   322→
   323→// ReadSessionFromPath is a convenience method that reads a session directly from a file path.
   324→// This is useful when you have the path but not a HookInput.
   325→func (c *ClaudeCodeAgent) ReadSessionFromPath(transcriptPath, sessionID string) (*agent.AgentSession, error) {
   326→	return c.ReadSession(&agent.HookInput{
   327→		SessionID:  sessionID,
   328→		SessionRef: transcriptPath,
   329→	})
   330→}
   331→
   332→// SanitizePathForClaude converts a path to Claude's project directory format.
   333→// Claude replaces any non-alphanumeric character with a dash.
   334→var nonAlphanumericRegex = regexp.MustCompile(`[^a-zA-Z0-9]`)
   335→
   336→func SanitizePathForClaude(path string) string {
   337→	return nonAlphanumericRegex.ReplaceAllString(path, "-")
   338→}
   339→
