   202→
   203→// ReadSession reads a session from Gemini's storage (JSON transcript file).
   204→// The session data is stored in NativeData as raw JSON bytes.
   205→func (g *GeminiCLIAgent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) {
   206→	if input.SessionRef == "" {
   207→		return nil, errors.New("session reference (transcript path) is required")
   208→	}
   209→
   210→	// Read the raw JSON file
   211→	data, err := os.ReadFile(input.SessionRef)
   212→	if err != nil {
   213→		return nil, fmt.Errorf("failed to read transcript: %w", err)
   214→	}
   215→
   216→	// Parse to extract computed fields
   217→	modifiedFiles, err := ExtractModifiedFiles(data)
   218→	if err != nil {
   219→		// Non-fatal: we can still return the session without modified files
   220→		modifiedFiles = nil
   221→	}
   222→
   223→	return &agent.AgentSession{
   224→		SessionID:     input.SessionID,
   225→		AgentName:     g.Name(),
   226→		SessionRef:    input.SessionRef,
